// ============================================
// SETUP: Generar UUID + Extraer imagen a base64
// ============================================
const crypto = require('crypto');

// Generar ID único para esta cotización
const cotizacion_id = crypto.randomUUID();
const fecha = new Date().toISOString();

// Normalizar body (puede venir en .body o en raíz)
const body = $input.first().json.body || $input.first().json;
const nombre   = (body.nombre   || '').trim();
const telefono = (body.telefono || '').trim();
const colegio  = (body.colegio  || '').trim();
const grado    = (body.grado    || '').trim();

// Validar campos requeridos
if (!nombre)   throw new Error('Campo requerido: nombre');
if (!telefono) throw new Error('Campo requerido: telefono');

// Extraer y codificar archivo binario
const item = $input.first();
const binaryKeys = Object.keys(item.binary || {});

if (binaryKeys.length === 0) {
  throw new Error('No se encontro archivo adjunto en la solicitud');
}

const binaryKey    = binaryKeys[0];
const binaryBuffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
const base64Image  = binaryBuffer.toString('base64');
const mimeType     = item.binary[binaryKey].mimeType || 'image/jpeg';
const fileName     = item.binary[binaryKey].fileName  || 'lista_utiles';

// imageDataUrl necesario para OpenAI Vision API
return [{
  json: {
    cotizacion_id,
    fecha,
    nombre,
    telefono,
    colegio,
    grado,
    base64Image,
    mimeType,
    fileName,
    imageDataUrl: `data:${mimeType};base64,${base64Image}`
  }
}];

// ============================================
// PREPARAR REQUEST OPENAI VISION
// ============================================

// Recuperar datos del nodo Setup (cotización + imagen)
const setup = $('Setup: UUID + Imagen').first().json;

// Recuperar catálogo completo desde Google Sheets
// El input actual son los items del catálogo
const catalogoItems = $input.all();
const productosNormalizados = [
  ...new Set(
    catalogoItems
      .map(item => (item.json.producto_normalizado || '').trim())
      .filter(v => v !== '')
  )
].sort();

if (productosNormalizados.length === 0) {
  throw new Error('El catalogo de productos esta vacio. Verifica la Sheet "productos".');
}

// Construir prompt con lista de productos autorizada
const listaProductos = JSON.stringify(productosNormalizados, null, 2);

const prompt = `Eres un asistente especializado en identificar utiles escolares en listas de utiles peruanas.\n\nExtrae unicamente los utiles escolares listados en el documento adjunto.\nSolo puedes devolver productos que existan EXACTAMENTE en esta lista autorizada:\n\n{{LISTA_PRODUCTOS}}\n\nREGLAS ESTRICTAS:\n1. Usa EXACTAMENTE el codigo de la lista autorizada (sin modificar)\n2. Si un producto no esta en la lista, omitelo completamente\n3. Extrae la cantidad indicada; si no hay cantidad, usa 1\n4. No inventes productos ni variaciones\n5. No agregues texto, explicaciones ni markdown\n\nDevuelve UNICAMENTE este JSON (sin codigo fence, sin texto adicional):\n[\n  { "producto": "codigo_exacto", "cantidad": 1 }\n]`
  .replace('{{LISTA_PRODUCTOS}}', listaProductos);

// Construir request body para OpenAI Vision API
const requestBody = {
  model: 'gpt-4o',
  max_tokens: 2000,
  temperature: 0,
  messages: [{
    role: 'user',
    content: [
      {
        type: 'text',
        text: prompt
      },
      {
        type: 'image_url',
        image_url: {
          url: setup.imageDataUrl,
          detail: 'high'
        }
      }
    ]
  }]
};

return [{
  json: {
    ...setup,
    requestBody
  }
}];

// ============================================
// PARSEAR RESPUESTA OPENAI + CALCULAR TOTALES
// ============================================

// 1. Respuesta cruda de OpenAI
const openaiResp = $input.first().json;
const rawContent = openaiResp.choices?.[0]?.message?.content || '';

// 2. Datos originales del cliente (desde nodo Setup)
const setup = $('Setup: UUID + Imagen').first().json;

// 3. Catálogo completo de productos (desde Google Sheets)
const catalogoItems = $('Obtener Catalogo').all();

// Construir mapa de precios: { "codigo": { "marca": 5.50, "economico": 3.20 } }
const precioMap = {};
for (const item of catalogoItems) {
  const p      = item.json;
  const codigo = (p.producto_normalizado || '').trim();
  const tipo   = (p.tipo || '').trim().toLowerCase();
  const precio = parseFloat(p.precio) || 0;

  if (!codigo || !tipo || precio <= 0) continue;

  if (!precioMap[codigo]) precioMap[codigo] = {};
  precioMap[codigo][tipo] = precio;
}

// 4. Parsear JSON devuelto por OpenAI
let productosDetectados = [];
try {
  // Limpiar posibles code fences de markdown
  const cleaned = rawContent
    .replace(/```json\s*/gi, '')
    .replace(/```\s*/gi, '')
    .trim();
  const parsed = JSON.parse(cleaned);
  if (Array.isArray(parsed)) productosDetectados = parsed;
} catch (e) {
  // Parse fallido -> array vacío, no rompe el flujo
  productosDetectados = [];
}

// 5. Calcular totales cruzando con el catálogo
let total_marca     = 0;
let total_economico = 0;
const productos_cotizados     = [];
const productos_no_encontrados = [];

for (const det of productosDetectados) {
  const codigo   = (det.producto || '').trim();
  const cantidad = Math.max(1, parseInt(det.cantidad) || 1);

  if (!codigo) continue;

  const precios = precioMap[codigo];
  if (!precios) {
    // Producto detectado por IA pero no existe en catálogo -> ignorar
    productos_no_encontrados.push(codigo);
    continue;
  }

  const precio_marca     = precios['marca']     || 0;
  const precio_economico = precios['economico'] || 0;

  // Validar que AMBOS precios existan y sean > 0
  if (precio_marca <= 0 || precio_economico <= 0) {
    productos_no_encontrados.push(`${codigo} (precio incompleto)`);
    continue;
  }

  const sub_marca     = Math.round(precio_marca     * cantidad * 100) / 100;
  const sub_economico = Math.round(precio_economico * cantidad * 100) / 100;

  total_marca     += sub_marca;
  total_economico += sub_economico;

  productos_cotizados.push({
    producto:          codigo,
    cantidad,
    precio_marca,
    precio_economico,
    subtotal_marca:     sub_marca,
    subtotal_economico: sub_economico
  });
}

// Redondear totales finales
total_marca     = Math.round(total_marca     * 100) / 100;
total_economico = Math.round(total_economico * 100) / 100;

return [{
  json: {
    cotizacion_id:          setup.cotizacion_id,
    fecha:                  setup.fecha,
    nombre:                 setup.nombre,
    telefono:               setup.telefono,
    colegio:                setup.colegio,
    grado:                  setup.grado,
    total_marca,
    total_economico,
    productos_cotizados,
    productos_no_encontrados,
    num_productos:          productos_cotizados.length,
    tiene_productos:        productos_cotizados.length > 0,
    estado:                 'cotizado'
  }
}];

// ============================================
// PREPARAR MENSAJES TELEGRAM (LEADS + ADMIN)
// ============================================
const d = $input.first().json;

// Lista de productos para ADMIN
const listaProductos = d.productos_cotizados
  .map(p =>
    `  • *${p.producto}* ×${p.cantidad}` +
    ` → Marca: S/${p.subtotal_marca.toFixed(2)}` +
    ` / Eco: S/${p.subtotal_economico.toFixed(2)}`
  )
  .join('\n') || '  (Sin productos válidos identificados)';

const noEncontrados = d.productos_no_encontrados.length > 0
  ? '\n⚠️ _No encontrados_: ' +
    d.productos_no_encontrados.slice(0, 5).join(', ') +
    (d.productos_no_encontrados.length > 5 ? '...' : '')
  : '';

// === Mensaje LEADS: resumen simple ===
const msg_leads = [
  '🆕 *Nueva Cotización*',
  '🆔 `' + d.cotizacion_id.slice(0, 8) + '...`',
  '👤 ' + d.nombre + ' | 📞 ' + d.telefono,
  '🏫 ' + (d.colegio || 'N/A') + ' — ' + (d.grado || 'N/A'),
  '💰 Marca: *S/ ' + d.total_marca.toFixed(2) + '*',
  '💰 Económica: *S/ ' + d.total_economico.toFixed(2) + '*',
  '📦 ' + d.num_productos + ' producto(s)'
].join('\n');

// === Mensaje ADMIN: detalle completo ===
const msg_admin = [
  '📋 *NUEVA COTIZACIÓN — Detalle Completo*',
  '━━━━━━━━━━━━━━━━━━━',
  '🆔 `' + d.cotizacion_id + '`',
  '📅 ' + new Date(d.fecha).toLocaleString('es-PE', { timeZone: 'America/Lima' }),
  '━━━━━━━━━━━━━━━━━━━',
  '👤 ' + d.nombre,
  '📞 ' + d.telefono,
  '🏫 ' + (d.colegio || 'N/A') + ' — ' + (d.grado || 'N/A'),
  '━━━━━━━━━━━━━━━━━━━',
  '📦 *Productos (' + d.num_productos + '):*',
  listaProductos,
  noEncontrados,
  '━━━━━━━━━━━━━━━━━━━',
  '💰 *Total Marca: S/ ' + d.total_marca.toFixed(2) + '*',
  '💰 *Total Económica: S/ ' + d.total_economico.toFixed(2) + '*'
].filter(Boolean).join('\n');

return [{
  json: {
    ...d,
    msg_leads,
    msg_admin
  }
}];
